(function(){"use strict";function initButton(){var buttonPath=document.querySelector('.smooth-back-to-top-button path, .smooth-back-to-top-button rect');if(!buttonPath){return}
var pathLength=buttonPath.getTotalLength();buttonPath.style.strokeDasharray=pathLength+' '+pathLength;buttonPath.style.strokeDashoffset=pathLength;var isTicking=!1;var updateButtonProgress=function(){var scroll=window.scrollY;var height=document.documentElement.scrollHeight-window.innerHeight;var progress=height>0?pathLength-(scroll*pathLength/height):pathLength;buttonPath.style.strokeDashoffset=progress;isTicking=!1};var onScroll=function(){if(!isTicking){window.requestAnimationFrame(updateButtonProgress);isTicking=!0}};updateButtonProgress();window.addEventListener('scroll',onScroll,{passive:!0})}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initButton)}else{initButton()}})()